public ViewResult Index(string category = null)
    {
        var products = new[]
        {
            new Product(){ Name="Kayak", Category="Watersports"},
            new Product(){ Name="Lifejacket", Category="Watersports"},
            new Product(){ Name="Soccer ball", Category="Soccer"},
            new Product(){ Name="Corner flag", Category="Soccer"}
        };

        if (category == "Soccer")
        {
             return Content(string.Join(",", products.Where(p => p.Category == "Soccer").Select(x=> x.Name)));
        }
        else{
            return Content(string.Join(", ",products.Select(c => c.Name)));
        }
    }
